#Requires -Version 5.1
#Requires -RunAsAdministrator
<#
.SYNOPSIS
    Gutachten-Manager — Automatischer Installer
    Richtet alles ein: WSL2, Docker Desktop, Anwendung, Shortcuts und Shell-Tool.

.DESCRIPTION
    Dieses Skript installiert den Gutachten-Manager vollstaendig automatisch.
    Es werden alle notwendigen Komponenten heruntergeladen und konfiguriert.

    VORAUSSETZUNGEN:
      - Windows 10 (Build 19041+) oder Windows 11
      - Internetverbindung (fuer Docker Desktop)
      - Administrator-Rechte

    ENTHALTENE KOMPONENTEN:
      - Gutachten-Manager Anwendung (bereits eingebettet)
      - Automatische WSL2-Einrichtung
      - Automatischer Docker Desktop Download und Installation

.NOTES
    Erstellt mit Claude Code — Gutachten-Manager Setup-Generator
#>

[CmdletBinding()]
param(
    [string]$InstallPfad = "$env:USERPROFILE\Gutachten-Manager"
)

$ErrorActionPreference = 'Stop'
$ProgressPreference    = 'Continue'

# ─── Farb-Ausgabe Helfer ──────────────────────────────────────────────────────
function Write-Banner {
    Clear-Host
    Write-Host ""
    Write-Host "  ╔════════════════════════════════════════════════════════════╗" -ForegroundColor Cyan
    Write-Host "  ║         GUTACHTEN-MANAGER  —  AUTOMATISCHER INSTALLER      ║" -ForegroundColor Cyan
    Write-Host "  ║              Fuer Sachverstaendige und Gutachter            ║" -ForegroundColor Cyan
    Write-Host "  ╚════════════════════════════════════════════════════════════╝" -ForegroundColor Cyan
    Write-Host ""
}

function Write-Step($nr, $text) {
    Write-Host ""
    Write-Host "  [$nr/7] $text" -ForegroundColor Yellow
    Write-Host "  ─────────────────────────────────────────────────────────────" -ForegroundColor DarkGray
}

function Write-OK($t)   { Write-Host "   ✓  $t" -ForegroundColor Green }
function Write-INF($t)  { Write-Host "      $t" -ForegroundColor Gray }
function Write-WARN($t) { Write-Host "   !  $t" -ForegroundColor Yellow }
function Write-ERR($t)  { Write-Host "  ✗  FEHLER: $t" -ForegroundColor Red }

function Wait-Key($msg = "Weiter mit beliebiger Taste...") {
    Write-Host ""
    Write-Host "  $msg" -ForegroundColor DarkCyan
    $null = $Host.UI.RawUI.ReadKey("NoEcho,IncludeKeyDown")
}

function Download-File($url, $dest, $desc) {
    Write-INF "Lade $desc herunter..."
    Write-INF "URL: $url"
    $webClient = New-Object System.Net.WebClient
    $webClient.Headers.Add("User-Agent", "Mozilla/5.0 (Windows NT 10.0; Win64; x64)")
    try {
        $webClient.DownloadFile($url, $dest)
        $size = [math]::Round((Get-Item $dest).Length / 1MB, 1)
        Write-OK "$desc heruntergeladen ($size MB)"
    } catch {
        # Fallback to BITS if WebClient fails
        try {
            Import-Module BitsTransfer -ErrorAction SilentlyContinue
            Start-BitsTransfer -Source $url -Destination $dest -DisplayName $desc
            $size = [math]::Round((Get-Item $dest).Length / 1MB, 1)
            Write-OK "$desc heruntergeladen ($size MB)"
        } catch {
            throw "Download fehlgeschlagen: $_"
        }
    }
}

# ─── SCHRITT 0: Vorbereitung ──────────────────────────────────────────────────
Write-Banner

Write-Host "  Installationspfad: " -NoNewline -ForegroundColor White
Write-Host $InstallPfad -ForegroundColor Cyan
Write-Host ""
Write-INF "Druecken Sie ENTER zum Starten oder Ctrl+C zum Abbrechen."
Read-Host | Out-Null

$TempDir = Join-Path $env:TEMP "gm_install_$(Get-Random)"
New-Item -ItemType Directory -Path $TempDir -Force | Out-Null

# ─── SCHRITT 1: Windows-Version pruefen ──────────────────────────────────────
Write-Step 1 "Systemanforderungen pruefen"

$os = Get-CimInstance Win32_OperatingSystem
$build = [int]$os.BuildNumber
$caption = $os.Caption

Write-INF "Betriebssystem: $caption (Build $build)"

if ($build -lt 19041) {
    Write-ERR "Windows 10 Build 19041 oder hoeher erforderlich."
    Write-ERR "Aktueller Build: $build"
    Write-INF "Bitte fuehren Sie ein Windows-Update durch."
    Wait-Key "Druecken Sie eine Taste zum Beenden."
    exit 1
}

Write-OK "Windows-Version kompatibel (Build $build)"

# Virtualisierung pruefen
$virt = Get-CimInstance -ClassName Win32_ComputerSystem | Select-Object -ExpandProperty HypervisorPresent
if ($virt) {
    Write-OK "Virtualisierung verfuegbar"
} else {
    Write-WARN "Virtualisierung moeglicherweise deaktiviert — bitte im BIOS pruefen."
}

# ─── SCHRITT 2: WSL2 einrichten ───────────────────────────────────────────────
Write-Step 2 "WSL2 einrichten (benoetigt fuer Docker Desktop)"

$wslOk = $false
try {
    $wslVer = (wsl --version 2>&1) -join ' '
    if ($LASTEXITCODE -eq 0 -and $wslVer -match 'WSL') {
        Write-OK "WSL2 ist bereits installiert"
        $wslOk = $true
    }
} catch {}

if (-not $wslOk) {
    Write-INF "WSL2 wird eingerichtet..."

    # Virtual Machine Platform aktivieren
    Write-INF "Aktiviere Virtual Machine Platform..."
    $result = dism.exe /online /enable-feature /featurename:VirtualMachinePlatform /all /norestart 2>&1
    if ($LASTEXITCODE -ne 0) {
        Write-WARN "Konnte Virtual Machine Platform nicht aktivieren: $result"
    } else {
        Write-OK "Virtual Machine Platform aktiviert"
    }

    # Microsoft-Windows-Subsystem-Linux aktivieren (fuer Build < 22000)
    if ($build -lt 22000) {
        Write-INF "Aktiviere Windows-Subsystem-Linux..."
        dism.exe /online /enable-feature /featurename:Microsoft-Windows-Subsystem-Linux /all /norestart 2>&1 | Out-Null
        Write-OK "WSL Feature aktiviert"
    }

    # WSL2 Kernel-Update herunterladen und installieren
    Write-INF "Lade WSL2 Kernel-Update herunter (~15 MB)..."
    $wslMsi = Join-Path $TempDir "wsl_update.msi"
    try {
        Download-File `
            "https://wslstorestorage.blob.core.windows.net/wslblob/wsl_update_x64.msi" `
            $wslMsi `
            "WSL2 Kernel-Update"
        
        Write-INF "Installiere WSL2 Kernel-Update..."
        $proc = Start-Process msiexec.exe -ArgumentList "/i `"$wslMsi`" /quiet /norestart" -Wait -PassThru
        if ($proc.ExitCode -eq 0) {
            Write-OK "WSL2 Kernel installiert"
        } else {
            Write-WARN "MSI Exitcode: $($proc.ExitCode) — Installation fortsetzen..."
        }
    } catch {
        Write-WARN "WSL2 Kernel-Download fehlgeschlagen: $_"
        Write-WARN "Moeglicherweise bereits vorhanden oder wird von Docker Desktop installiert."
    }

    # WSL2 als Standard setzen
    try {
        wsl --set-default-version 2 2>&1 | Out-Null
        Write-OK "WSL2 als Standard-Version gesetzt"
    } catch {
        Write-WARN "Konnte WSL2 nicht als Standard setzen: $_"
    }
}

# ─── SCHRITT 3: Docker Desktop pruefen / installieren ────────────────────────
Write-Step 3 "Docker Desktop pruefen und installieren"

$dockerInstalled = $false
$dockerPaths = @(
    "C:\Program Files\Docker\Docker\Docker Desktop.exe",
    "C:\Program Files\Docker\Docker\resources\bin\docker.exe"
)
foreach ($p in $dockerPaths) {
    if (Test-Path $p) { $dockerInstalled = $true; break }
}

# Auch PATH pruefen
if (-not $dockerInstalled) {
    try {
        $null = & docker --version 2>&1
        if ($LASTEXITCODE -eq 0) { $dockerInstalled = $true }
    } catch {}
}

if ($dockerInstalled) {
    Write-OK "Docker Desktop ist bereits installiert"
} else {
    Write-INF "Docker Desktop wird heruntergeladen (~600 MB)..."
    Write-WARN "Das kann einige Minuten dauern — bitte warten..."
    
    $dockerInstaller = Join-Path $TempDir "DockerDesktopInstaller.exe"
    
    $dockerUrls = @(
        "https://desktop.docker.com/win/main/amd64/Docker%20Desktop%20Installer.exe",
        "https://desktop.docker.com/win/stable/amd64/Docker%20Desktop%20Installer.exe"
    )
    
    $downloaded = $false
    foreach ($url in $dockerUrls) {
        try {
            Download-File $url $dockerInstaller "Docker Desktop"
            $downloaded = $true
            break
        } catch {
            Write-WARN "URL fehlgeschlagen: $url — versuche naechste..."
        }
    }
    
    if (-not $downloaded) {
        Write-ERR "Docker Desktop konnte nicht heruntergeladen werden."
        Write-INF ""
        Write-INF "Bitte manuell installieren:"
        Write-INF "  https://docs.docker.com/desktop/install/windows-install/"
        Write-INF ""
        Write-INF "Danach dieses Skript erneut ausfuehren."
        Wait-Key
        exit 1
    }
    
    Write-INF "Installiere Docker Desktop (Silent-Installation)..."
    Write-INF "Das dauert 3-8 Minuten..."
    
    $proc = Start-Process $dockerInstaller `
        -ArgumentList "install --quiet --accept-license --backend=wsl-2" `
        -Wait -PassThru
    
    if ($proc.ExitCode -eq 0 -or $proc.ExitCode -eq 3010) {
        Write-OK "Docker Desktop installiert (ExitCode: $($proc.ExitCode))"
        if ($proc.ExitCode -eq 3010) {
            Write-WARN "Ein Neustart wird empfohlen — Installation fuer jetzt fortgesetzt."
        }
    } else {
        Write-WARN "Docker Desktop Installer ExitCode: $($proc.ExitCode)"
        Write-WARN "Moeglicherweise trotzdem installiert — fahre fort..."
    }
}

# ─── SCHRITT 4: Anwendung entpacken ──────────────────────────────────────────
Write-Step 4 "Gutachten-Manager entpacken und installieren"

# Zielverzeichnis erstellen
if (Test-Path $InstallPfad) {
    Write-WARN "Verzeichnis existiert bereits: $InstallPfad"
    Write-WARN "Vorhandene Dateien werden aktualisiert (Datenbank bleibt erhalten)."
} else {
    New-Item -ItemType Directory -Path $InstallPfad -Force | Out-Null
    Write-OK "Verzeichnis erstellt: $InstallPfad"
}

# Eingebettetes ZIP entpacken
Write-INF "Entpacke Anwendungsdateien..."
$zipDest = Join-Path $TempDir "gutachten-manager.zip"

$b64 = ""

$bytes = [Convert]::FromBase64String($b64)
[IO.File]::WriteAllBytes($zipDest, $bytes)
Write-OK "ZIP dekodiert ($(($bytes.Length / 1KB) -as [int]) KB)"

Add-Type -Assembly System.IO.Compression.FileSystem
$zip = [IO.Compression.ZipFile]::OpenRead($zipDest)
$entryCount = $zip.Entries.Count
$zip.Dispose()

Write-INF "Entpacke $entryCount Dateien..."
Expand-Archive -Path $zipDest -DestinationPath $TempDir -Force

# Top-Level-Ordner im ZIP finden (z.B. "Gutachten-Manager")
$zipRoot = Get-ChildItem $TempDir -Directory | Select-Object -First 1
if (-not $zipRoot) {
    Write-ERR "ZIP-Struktur ungueltig — kein Unterordner gefunden."
    exit 1
}

# Dateien ins Zielverzeichnis kopieren
Write-INF "Kopiere Dateien nach $InstallPfad..."
Get-ChildItem $zipRoot.FullName | Copy-Item -Destination $InstallPfad -Recurse -Force
Write-OK "$entryCount Dateien entpackt und kopiert"

# ─── SCHRITT 5: Konfiguration ─────────────────────────────────────────────────
Write-Step 5 "Anwendung konfigurieren"

$envFile    = Join-Path $InstallPfad ".env"
$envExample = Join-Path $InstallPfad ".env.example"

if (-not (Test-Path $envFile)) {
    if (Test-Path $envExample) {
        Copy-Item $envExample $envFile
        Write-OK ".env Konfigurationsdatei erstellt"
        Write-INF "Standard-Konfiguration wird verwendet."
        Write-INF "Fuer Produktivbetrieb: $envFile anpassen."
    } else {
        # Minimale .env erstellen
        @"
# Gutachten-Manager Konfiguration
NODE_ENV=production
PORT=4000

POSTGRES_HOST=db
POSTGRES_PORT=5432
POSTGRES_DB=gutachten_manager
POSTGRES_USER=gutachten_user
POSTGRES_PASSWORD=GutachtenManager2024!

DATABASE_URL=postgresql://gutachten_user:GutachtenManager2024!@db:5432/gutachten_manager

JWT_SECRET=GutachtenManagerJWT2024ChangeInProduction
JWT_REFRESH_SECRET=GutachtenManagerRefreshJWT2024Change

UPLOAD_MAX_SIZE=52428800
LOG_LEVEL=info
"@ | Set-Content $envFile -Encoding UTF8
        Write-OK ".env mit Standard-Konfiguration erstellt"
    }
} else {
    Write-OK ".env existiert bereits — unveraendert"
}

# Berechtigungen auf Datenbank-Passwort setzen
try {
    $acl = Get-Acl $envFile
    $acl.SetAccessRuleProtection($true, $false)
    $rule = New-Object Security.AccessControl.FileSystemAccessRule(
        $env:USERNAME, "FullControl", "Allow")
    $acl.AddAccessRule($rule)
    Set-Acl $envFile $acl
    Write-OK ".env abgesichert (nur aktueller Benutzer)"
} catch {
    Write-INF ".env Berechtigungen nicht gesetzt: $_"
}

# ─── SCHRITT 6: Desktop-Verknuepfungen + Shell-Tool ──────────────────────────
Write-Step 6 "Desktop-Verknuepfungen und Shell-Tool einrichten"

$desktop = [Environment]::GetFolderPath("Desktop")
$wshShell = New-Object -ComObject WScript.Shell

# Hilfsfunktion fuer .lnk Shortcut
function New-Shortcut($name, $target, $args, $icon, $desc) {
    $lnk  = Join-Path $desktop "$name.lnk"
    $link = $wshShell.CreateShortcut($lnk)
    $link.TargetPath       = $target
    $link.Arguments        = $args
    $link.WorkingDirectory = $InstallPfad
    $link.Description      = $desc
    if ($icon) { $link.IconLocation = $icon }
    $link.Save()
    Write-OK "Verknuepfung erstellt: $name"
}

# STARTEN
New-Shortcut `
    "Gutachten-Manager STARTEN" `
    (Join-Path $InstallPfad "STARTEN.bat") `
    "" `
    "C:\Windows\System32\shell32.dll,137" `
    "Gutachten-Manager starten"

# BEENDEN
New-Shortcut `
    "Gutachten-Manager BEENDEN" `
    (Join-Path $InstallPfad "BEENDEN.bat") `
    "" `
    "C:\Windows\System32\shell32.dll,131" `
    "Gutachten-Manager stoppen"

# STATUS
New-Shortcut `
    "Gutachten-Manager STATUS" `
    (Join-Path $InstallPfad "STATUS.bat") `
    "" `
    "C:\Windows\System32\shell32.dll,21" `
    "Gutachten-Manager Status anzeigen"

# gm Shell-Funktion in PowerShell-Profil registrieren
Write-INF "Registriere 'gm' Shell-Befehl in PowerShell-Profil..."

$profileDir = Split-Path $PROFILE
if (-not (Test-Path $profileDir)) {
    New-Item -ItemType Directory -Path $profileDir -Force | Out-Null
}
if (-not (Test-Path $PROFILE)) {
    New-Item -ItemType File -Path $PROFILE -Force | Out-Null
}

$gmPfad      = (Join-Path $InstallPfad "maintenance\gm.ps1").Replace('\','\\')
$profileCode = @"

# ── Gutachten-Manager CLI ────────────────────────────────────────
# Installiert von Gutachten-Manager-Setup.ps1
function gm {
    param([Parameter(ValueFromRemainingArguments)][string[]]`$args)
    & "$gmPfad" @args
}
# ──────────────────────────────────────────────────────────────────
"@

# Bereits eingetragen?
$profileContent = if (Test-Path $PROFILE) { Get-Content $PROFILE -Raw } else { '' }
if ($profileContent -notmatch 'Gutachten-Manager CLI') {
    Add-Content $PROFILE $profileCode -Encoding UTF8
    Write-OK "'gm' Befehl in Profil registriert: $PROFILE"
} else {
    Write-OK "'gm' Befehl bereits im Profil registriert"
}

# Auch in aktueller Session verfuegbar machen
$gmScript = Join-Path $InstallPfad "maintenance\gm.ps1"
if (Test-Path $gmScript) {
    Set-Alias -Name gm -Value $gmScript -Scope Global -ErrorAction SilentlyContinue
    Write-OK "'gm' in aktueller Sitzung verfuegbar"
}

# ─── SCHRITT 7: Anwendung erstellen und starten ───────────────────────────────
Write-Step 7 "Docker Images bauen und Anwendung starten"

# Docker starten falls nicht aktiv
Write-INF "Pruefen ob Docker laeuft..."
$dockerRunning = $false
$maxWait = 120
$waited  = 0

# Docker Desktop Prozess starten
$dockerExe = "C:\Program Files\Docker\Docker\Docker Desktop.exe"
if (Test-Path $dockerExe) {
    $running = Get-Process "Docker Desktop" -ErrorAction SilentlyContinue
    if (-not $running) {
        Write-INF "Starte Docker Desktop..."
        Start-Process $dockerExe
        Write-INF "Warte bis Docker Desktop bereit ist (bis zu 120 Sekunden)..."
    }
}

while ($waited -lt $maxWait) {
    $result = docker ps 2>&1
    if ($LASTEXITCODE -eq 0) {
        $dockerRunning = $true
        break
    }
    Start-Sleep 5
    $waited += 5
    Write-Host "." -NoNewline -ForegroundColor DarkGray
}

if (-not $dockerRunning) {
    Write-Host ""
    Write-WARN "Docker Desktop ist noch nicht bereit."
    Write-WARN "Bitte Docker Desktop manuell starten und dann STARTEN.bat ausfuehren."
    Write-INF ""
    Write-INF "Verknuepfungen wurden auf dem Desktop erstellt."
    Write-INF "Nach dem Docker-Start: Doppelklick auf 'Gutachten-Manager STARTEN'"
    Wait-Key "Taste druecken zum Beenden..."
    exit 0
}

Write-Host ""
Write-OK "Docker laeuft!"

Set-Location $InstallPfad

Write-INF ""
Write-INF "Baue Docker-Images (kann 10-20 Minuten dauern beim ersten Mal)..."
Write-INF "Bitte nicht unterbrechen — Abhängigkeiten werden heruntergeladen."
Write-INF ""

# Build mit Ausgabe
$buildProc = Start-Process "docker" `
    -ArgumentList "compose up --build -d" `
    -WorkingDirectory $InstallPfad `
    -NoNewWindow -Wait -PassThru

if ($buildProc.ExitCode -ne 0) {
    Write-ERR "Docker Build fehlgeschlagen (ExitCode: $($buildProc.ExitCode))"
    Write-INF ""
    Write-INF "Diagnose-Logs:"
    & docker compose logs --tail=30 2>&1 | ForEach-Object { Write-INF $_ }
    Write-INF ""
    Write-INF "Haufige Probleme:"
    Write-INF "  1. Internet-Verbindung pruefen"
    Write-INF "  2. Ausreichend Speicherplatz (mind. 5 GB) pruefen"
    Write-INF "  3. Docker Desktop neu starten"
    Write-INF "  4. Dann erneut STARTEN.bat ausfuehren"
    Wait-Key
    exit 1
}

Write-OK "Docker Build erfolgreich!"
Write-INF "Warte bis Anwendung bereit ist..."

# Health-Check
$attempts = 0
$ready    = $false
while ($attempts -lt 40) {
    $attempts++
    try {
        $r = Invoke-WebRequest "http://localhost/api/v1/health" `
            -UseBasicParsing -TimeoutSec 3 -ErrorAction Stop
        if ($r.StatusCode -eq 200) { $ready = $true; break }
    } catch {}
    Start-Sleep 5
    Write-Host "." -NoNewline -ForegroundColor DarkGray
}
Write-Host ""

# ─── FERTIG! ──────────────────────────────────────────────────────────────────
Write-Banner

if ($ready) {
    Write-Host "  ╔════════════════════════════════════════════════════════════╗" -ForegroundColor Green
    Write-Host "  ║      INSTALLATION ERFOLGREICH ABGESCHLOSSEN!               ║" -ForegroundColor Green
    Write-Host "  ╚════════════════════════════════════════════════════════════╝" -ForegroundColor Green
    Write-Host ""
    Write-Host "   Gutachten-Manager ist jetzt erreichbar:" -ForegroundColor White
    Write-Host ""
    Write-Host "     http://localhost" -ForegroundColor Cyan
    Write-Host ""
    Start-Process "http://localhost"
} else {
    Write-Host "  ╔════════════════════════════════════════════════════════════╗" -ForegroundColor Yellow
    Write-Host "  ║   INSTALLATION ABGESCHLOSSEN — App startet noch...         ║" -ForegroundColor Yellow
    Write-Host "  ╚════════════════════════════════════════════════════════════╝" -ForegroundColor Yellow
    Write-Host ""
    Write-Host "   Bitte in 2 Minuten oeffnen: http://localhost" -ForegroundColor White
}

Write-Host ""
Write-Host "  INSTALLATIONSPFAD:   $InstallPfad" -ForegroundColor White
Write-Host "  KONFIGURATION:       $InstallPfad\.env" -ForegroundColor White
Write-Host "  LOGS:                $InstallPfad\logs\" -ForegroundColor White
Write-Host "  BACKUPS:             $InstallPfad\backups\" -ForegroundColor White
Write-Host ""
Write-Host "  DESKTOP-VERKNUEPFUNGEN:" -ForegroundColor White
Write-Host "    Gutachten-Manager STARTEN   — Anwendung starten" -ForegroundColor Gray
Write-Host "    Gutachten-Manager BEENDEN   — Anwendung stoppen" -ForegroundColor Gray
Write-Host "    Gutachten-Manager STATUS    — Status anzeigen" -ForegroundColor Gray
Write-Host ""
Write-Host "  SHELL-WARTUNG (in PowerShell):" -ForegroundColor White
Write-Host "    gm status          — Container-Status" -ForegroundColor Gray
Write-Host "    gm logs            — Live-Logs" -ForegroundColor Gray
Write-Host "    gm backup          — Datenbank sichern" -ForegroundColor Gray
Write-Host "    gm restore         — Datenbank wiederherstellen" -ForegroundColor Gray
Write-Host "    gm rebuild         — Images neu bauen" -ForegroundColor Gray
Write-Host "    gm help            — Alle Befehle" -ForegroundColor Gray
Write-Host ""
Write-Host "  ─────────────────────────────────────────────────────────────" -ForegroundColor DarkGray
Write-Host ""

# Aufraeumen
Remove-Item $TempDir -Recurse -Force -ErrorAction SilentlyContinue

Wait-Key "Taste druecken zum Schliessen..."
